// src/pages/WalletPage.js
// BidZone Wallet – accessible by all authenticated users
// Shows balance, transaction history, withdrawal request (sellers)

import React, { useState, useEffect, useContext } from 'react';
import { walletAPI } from '../services/api';
import { AuthContext } from '../context/AuthContext';

const WalletPage = () => {
  const { user } = useContext(AuthContext);
  const [wallet, setWallet]         = useState(null);
  const [loading, setLoading]       = useState(true);
  const [wdForm, setWdForm]         = useState({ amount: '', upi_id: '' });
  const [wdMsg, setWdMsg]           = useState({ type: '', text: '' });
  const [wdLoading, setWdLoading]   = useState(false);
  const [showWd, setShowWd]         = useState(false);
  const [myWithdrawals, setMyWd]    = useState([]);

  const fetchWallet = async () => {
    setLoading(true);
    try {
      const res = await walletAPI.myWallet();
      setWallet(res.data);
    } catch { }
    setLoading(false);
  };

  const fetchWithdrawals = async () => {
    try {
      const res = await walletAPI.myWithdrawals();
      setMyWd(res.data.results || res.data);
    } catch { }
  };

  useEffect(() => { fetchWallet(); fetchWithdrawals(); }, []);

  const handleWithdraw = async (e) => {
    e.preventDefault();
    setWdLoading(true);
    setWdMsg({ type: '', text: '' });
    try {
      const res = await walletAPI.requestWithdrawal(wdForm);
      setWdMsg({ type: 'success', text: res.data.message });
      setWdForm({ amount: '', upi_id: '' });
      setShowWd(false);
      fetchWallet();
      fetchWithdrawals();
    } catch (err) {
      const d = err.response?.data;
      setWdMsg({ type: 'danger', text: typeof d === 'object' ? Object.values(d).flat().join(' ') : 'Request failed.' });
    }
    setWdLoading(false);
  };

  const txColor = (type) => type === 'CREDIT' ? '#28a745' : '#e94560';
  const txIcon  = (type) => type === 'CREDIT' ? 'bi-arrow-down-circle-fill' : 'bi-arrow-up-circle-fill';

  if (loading) return (
    <div className="min-vh-100 d-flex align-items-center justify-content-center">
      <div className="spinner-border" style={{ color: '#e94560' }}></div>
    </div>
  );

  return (
    <div className="min-vh-100" style={{ background: '#f0f2f5' }}>
      {/* Header */}
      <div className="py-4 text-white" style={{ background: 'linear-gradient(135deg, #1a1a2e, #0f3460)' }}>
        <div className="container">
          <h2 className="fw-bold mb-1">
            <i className="bi bi-wallet2 me-2" style={{ color: '#e94560' }}></i>BidZone Wallet
          </h2>
          <p className="mb-0 opacity-75">Your earnings, transactions & withdrawals</p>
        </div>
      </div>

      <div className="container py-4">
        {wdMsg.text && (
          <div className={`alert alert-${wdMsg.type} mb-4`}>{wdMsg.text}</div>
        )}

        <div className="row g-4">
          {/* Balance Card */}
          <div className="col-md-4">
            <div className="card border-0 shadow-sm text-center p-4" style={{ borderRadius: '16px' }}>
              <div className="mb-3">
                <div style={{
                  width: 80, height: 80, borderRadius: '50%',
                  background: 'linear-gradient(135deg, #e94560, #0f3460)',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  margin: '0 auto'
                }}>
                  <i className="bi bi-wallet2 text-white fs-2"></i>
                </div>
              </div>
              <h6 className="text-muted mb-1">Available Balance</h6>
              <h2 className="fw-bold mb-0" style={{ color: '#28a745' }}>
                ₹{wallet ? parseFloat(wallet.balance).toLocaleString('en-IN', { minimumFractionDigits: 2 }) : '0.00'}
              </h2>
              <p className="text-muted small mt-1">BidZone Wallet</p>

              {user?.role === 'SELLER' && (
                <button
                  className="btn fw-bold mt-3 w-100"
                  style={{ backgroundColor: '#e94560', color: 'white', borderRadius: '8px' }}
                  onClick={() => setShowWd(!showWd)}
                  disabled={!wallet || parseFloat(wallet.balance) <= 0}
                >
                  <i className="bi bi-bank me-2"></i>Withdraw to Bank
                </button>
              )}
            </div>

            {/* Withdrawal Form */}
            {showWd && user?.role === 'SELLER' && (
              <div className="card border-0 shadow-sm p-4 mt-3" style={{ borderRadius: '16px' }}>
                <h6 className="fw-bold mb-3">
                  <i className="bi bi-send me-2" style={{ color: '#e94560' }}></i>Withdraw via UPI
                </h6>
                <form onSubmit={handleWithdraw}>
                  <div className="mb-3">
                    <label className="form-label fw-semibold small">Amount (₹)</label>
                    <input
                      type="number" className="form-control" min="1"
                      max={wallet?.balance} step="0.01"
                      placeholder="Enter amount"
                      value={wdForm.amount}
                      onChange={e => setWdForm({ ...wdForm, amount: e.target.value })}
                      required
                    />
                    <small className="text-muted">Available: ₹{parseFloat(wallet?.balance || 0).toLocaleString()}</small>
                  </div>
                  <div className="mb-3">
                    <label className="form-label fw-semibold small">Your UPI ID</label>
                    <input
                      type="text" className="form-control"
                      placeholder="e.g. name@upi or 9876543210@paytm"
                      value={wdForm.upi_id}
                      onChange={e => setWdForm({ ...wdForm, upi_id: e.target.value })}
                      required
                    />
                  </div>
                  <div className="d-flex gap-2">
                    <button type="submit" className="btn fw-bold flex-fill"
                      style={{ backgroundColor: '#e94560', color: 'white' }} disabled={wdLoading}>
                      {wdLoading ? <span className="spinner-border spinner-border-sm"></span> : 'Submit Request'}
                    </button>
                    <button type="button" className="btn btn-light" onClick={() => setShowWd(false)}>Cancel</button>
                  </div>
                  <p className="text-muted small mt-2 mb-0">
                    <i className="bi bi-info-circle me-1"></i>
                    Processed within 24–48 hours by BidZone admin.
                  </p>
                </form>
              </div>
            )}

            {/* Withdrawal History */}
            {myWithdrawals.length > 0 && (
              <div className="card border-0 shadow-sm p-3 mt-3" style={{ borderRadius: '16px' }}>
                <h6 className="fw-bold mb-3">Withdrawal History</h6>
                {myWithdrawals.map(w => (
                  <div key={w.id} className="d-flex justify-content-between align-items-center py-2 border-bottom">
                    <div>
                      <div className="fw-semibold small">₹{parseFloat(w.amount).toLocaleString()}</div>
                      <div className="text-muted" style={{ fontSize: '0.75rem' }}>{w.upi_id}</div>
                      <div className="text-muted" style={{ fontSize: '0.7rem' }}>{new Date(w.created_at).toLocaleDateString()}</div>
                    </div>
                    <span className={`badge bg-${w.status === 'APPROVED' ? 'success' : w.status === 'REJECTED' ? 'danger' : 'warning'}`}>
                      {w.status}
                    </span>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Transaction History */}
          <div className="col-md-8">
            <div className="card border-0 shadow-sm" style={{ borderRadius: '16px' }}>
              <div className="card-header bg-white border-0 p-4">
                <h5 className="fw-bold mb-0">
                  <i className="bi bi-list-ul me-2" style={{ color: '#e94560' }}></i>Transaction History
                </h5>
              </div>
              <div className="card-body p-0">
                {!wallet || wallet.transactions.length === 0 ? (
                  <div className="text-center py-5">
                    <i className="bi bi-inbox fs-1 text-muted"></i>
                    <h6 className="mt-3 text-muted">No transactions yet</h6>
                  </div>
                ) : (
                  <div style={{ maxHeight: '480px', overflowY: 'auto' }}>
                    {wallet.transactions.map(tx => (
                      <div key={tx.id} className="d-flex align-items-center p-3 border-bottom">
                        <div className="me-3">
                          <i className={`bi ${txIcon(tx.transaction_type)} fs-4`}
                            style={{ color: txColor(tx.transaction_type) }}></i>
                        </div>
                        <div className="flex-fill">
                          <div className="fw-semibold small">{tx.description || tx.ref_id}</div>
                          <div className="text-muted" style={{ fontSize: '0.75rem' }}>
                            {new Date(tx.created_at).toLocaleString()}
                          </div>
                        </div>
                        <div className="text-end">
                          <div className="fw-bold" style={{ color: txColor(tx.transaction_type) }}>
                            {tx.transaction_type === 'CREDIT' ? '+' : '-'}₹{parseFloat(tx.amount).toLocaleString('en-IN', { minimumFractionDigits: 2 })}
                          </div>
                          <span className={`badge ${tx.transaction_type === 'CREDIT' ? 'bg-success' : 'bg-danger'}`}
                            style={{ fontSize: '0.65rem' }}>{tx.transaction_type}</span>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default WalletPage;
